import{_ as e}from"./chunks/panel-http-rule-form.BRe8ZX4N.js";import{_ as a,o as d,c as r,a2 as l}from"./chunks/framework.CuEaBji2.js";const o="/nginx-reverse-emby/screenshots/panel-http-rules.png",u=JSON.parse('{"title":"HTTP 反向代理","description":"","frontmatter":{},"headers":[],"relativePath":"guides/http-rules.md","filePath":"guides/http-rules.md","lastUpdated":1782021666000}'),i={name:"guides/http-rules.md"};function s(h,t,n,p,c,T){return d(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="http-反向代理" tabindex="-1">HTTP 反向代理 <a class="header-anchor" href="#http-反向代理" aria-label="Permalink to &quot;HTTP 反向代理&quot;">​</a></h1><p>HTTP 规则按域名把请求转发到后端服务，支持路径匹配、请求头注入、重定向改写和自动 HTTPS。适合 Emby、Jellyfin、网站等所有 Web 服务。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><ul><li>已 <a href="./../getting-started/deploy">部署控制面</a> 并能正常打开面板</li><li>入口域名已解析到运行规则的 Agent 节点</li><li>了解 <a href="./../getting-started/core-concepts">核心概念</a> 中的域名、端口和证书</li></ul><h2 id="创建-http-规则" tabindex="-1">创建 HTTP 规则 <a class="header-anchor" href="#创建-http-规则" aria-label="Permalink to &quot;创建 HTTP 规则&quot;">​</a></h2><p>进入 <strong>流量管理 → HTTP 规则</strong>，选好 Agent 节点（单机选 <code>local</code>），点击 <strong>添加规则</strong>。</p><p><img src="'+o+'" alt="HTTP 规则页面"></p><h3 id="基础配置" tabindex="-1">基础配置 <a class="header-anchor" href="#基础配置" aria-label="Permalink to &quot;基础配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>入口域名</td><td><code>app.example.com</code></td><td>选 <code>http://</code> 或 <code>https://</code>，填用户访问的域名</td></tr><tr><td>后端地址</td><td><code>http://192.168.1.100:8096</code></td><td>后端实际地址，带协议和端口</td></tr><tr><td>标签</td><td><code>emby</code></td><td>可选，方便在面板中筛选</td></tr><tr><td>启用规则</td><td>开</td><td>只有开启才会生效</td></tr></tbody></table><p><img src="'+e+`" alt="添加 HTTP 规则"></p><p>Agent 会在下次心跳同步时开始监听入口域名。如果你选了 HTTPS 入口，Agent 会自动申请证书（前提是 80 和 443 端口已放行）。</p><h3 id="高级选项" tabindex="-1">高级选项 <a class="header-anchor" href="#高级选项" aria-label="Permalink to &quot;高级选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>选项</th><th>说明</th></tr></thead><tbody><tr><td>代理 302/307 重定向</td><td>默认开启，把后端返回的跳转地址改写为入口域名。CDN 回源或 OAuth 回调场景需要关闭</td></tr><tr><td>出口 Profile</td><td>出站流量经过的代理，默认 <code>Direct</code> 直连。可选 SOCKS/HTTP 代理或 WireGuard</td></tr><tr><td>请求头</td><td>自定义发送给后端的请求头</td></tr><tr><td>Relay 配置</td><td>添加 Relay 隧道层，流量先经过中继节点再到后端。详见 <a href="./relay">Relay 隧道</a></td></tr></tbody></table><h2 id="验证规则" tabindex="-1">验证规则 <a class="header-anchor" href="#验证规则" aria-label="Permalink to &quot;验证规则&quot;">​</a></h2><p>浏览器打开入口域名。能正常看到后端页面就说明规则生效了。</p><p>打不开？按顺序查：</p><ol><li>DNS 是否指向 Agent 节点</li><li>节点端口是否放行（HTTP 80，HTTPS 443）</li><li>节点能否访问后端（<code>curl -I &lt;后端地址&gt;</code>）</li><li>规则是否选了正确的 Agent 且已启用</li></ol><p>更多排查见 <a href="./../operations/troubleshooting">排障指南</a>。</p><h2 id="启用-https" tabindex="-1">启用 HTTPS <a class="header-anchor" href="#启用-https" aria-label="Permalink to &quot;启用 HTTPS&quot;">​</a></h2><ol><li>把入口域名改成 <code>https://app.example.com</code></li><li>确认 80 和 443 端口已在防火墙放行</li><li>保存规则，Agent 会在同步时自动申请证书</li></ol><p>需要通配符证书或 80 端口不可用？见 <a href="./certificates">证书与 HTTPS</a>。</p><h2 id="给面板自身代理-https" tabindex="-1">给面板自身代理 HTTPS <a class="header-anchor" href="#给面板自身代理-https" aria-label="Permalink to &quot;给面板自身代理 HTTPS&quot;">​</a></h2><p>默认控制面只监听 <code>127.0.0.1:8080</code>。首次通过 SSH 隧道登录后，可以创建一条 HTTP 规则让面板给自己提供 HTTPS：</p><table tabindex="0"><thead><tr><th>字段</th><th>示例</th></tr></thead><tbody><tr><td>Agent</td><td><code>local</code></td></tr><tr><td>入口域名</td><td><code>https://panel.example.com</code></td></tr><tr><td>后端地址</td><td><code>http://127.0.0.1:8080</code></td></tr><tr><td>启用规则</td><td>开</td></tr></tbody></table><p>确认 <code>panel.example.com</code> 已解析到 VPS，并放行 80/443。规则生效后，访问 <code>https://panel.example.com</code> 就会由 local Agent 代理回控制面。</p><p>自代理 HTTPS 可用后，在 <code>docker-compose.yaml</code> 设置：</p><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  NRE_PUBLIC_URL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://panel.example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="流式恢复" tabindex="-1">流式恢复 <a class="header-anchor" href="#流式恢复" aria-label="Permalink to &quot;流式恢复&quot;">​</a></h2><p>HTTP 代理内置中断恢复机制：下载或播放中途断流时自动续传。后端需要支持 <code>Accept-Ranges: bytes</code> 并返回稳定的 <code>ETag</code> 或 <code>Last-Modified</code>。</p><p>相关环境变量见 <a href="./../reference/environment-variables">环境变量速查</a>。</p>`,30)])])}const g=a(i,[["render",s]]);export{u as __pageData,g as default};
